 datetime import datetime, timedelta\n\n# 结果目录\nresult_dir = \"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_10_macd_histogram_trend/independent/ga\"\n\ndef calculate_ema(series, period):\n    \"\"\"计算指数移动平均\"\"\"\n    return series.ewm(span=period, adjust=False).mean()\n\ndef calculate_macd(df):\n    \"\"\"计算MACD指标\n    返回包含DIFF, DEA, histogram的DataFrame\n    \"\"\"\n    # 计算EMA12和EMA26\n    ema12 = calculate_ema(df['close'], 12)\n    ema26 = calculate_ema(df['close'], 26)\n    \n    # DIFF = EMA12 - EMA26\n    diff = ema12 - ema26\n    \n    # DEA = 9日EMA(DIFF)\n    dea = calculate_ema(diff, 9)\n    \n    # histogram = DIFF - DEA\n    histogram = diff - dea\n    \n    df['DIFF'] = diff\n    df['DEA'] = dea\n    df['histogram'] = histogram\n    \n    return df\n\ndef check_consecutive_increase(histogram_values, start_idx):\n    \"\"\"检查从start_idx开始，连续5天histogram是否递增\"\"\"\n    if start_idx + 5 >= len(histogram_values):\n        return False\n    \n    for i in range(5):\n        if histogram_values[start_idx + i + 1] <= histogram_values[start_idx + i]:\n            return False\n    \n    return True\n\ndef analyze_stock(code, client):\n    \"\"\"分析单只股票是否满足条件\"\"\"\n    try:\n        # 获取90个交易日数据（预热30天+分析60天）\n        bars = client.bars(symbol=code, frequency=9, offset=90)\n        \n        if bars is None or len(bars) < 90:\n            return False\n        \n        # 按日期排序（从旧到新）\n        bars = bars.sort_index()\n        \n        # 计算MACD\n        bars = calculate_macd(bars)\n        \n        # 只分析最近60个交易日\n        analysis_window = bars.iloc[-60:]\n        histogram_values = analysis_window['histogram'].values\n        \n        # 查找histogram从负转正的位置\n        for i in range(len(histogram_values) - 1):\n            # 检测从负变正（金叉）\n            if histogram_values[i] < 0 and histogram_values[i + 1] > 0:\n                # 检查之后连续5天是否递增\n                if check_consecutive_increase(histogram_values, i + 1):\n                    return True\n        \n        return False\n        \n    except Exception as e:\n        print(f\"分析股票 {code} 时出错: {str(e)}\")\n        return False\n\ndef main():\n    print(\"开始分析创业板MACD柱状图趋势...\")\n    \n    # 初始化mootdx客户端\n    client = Quotes.factory(market='std')\n    \n    # 获取创业板股票列表（创业板代码以300开头）\n    print(\"获取创业板股票列表...\")\n    stock_list = client.stocks(market=1)  # market=1 是深圳市场\n    \n    if stock_list is None or len(stock_list) == 0:\n        print(\"无法获取股票列表\")\n        return\n    \n    # 筛选创业板股票（代码以300开头）\n    cyb_stocks = stock_list[stock_list['code'].str.startswith('300')]\n    print(f\"创业板股票总数: {len(cyb_stocks)}\")\n    \n    # 统计符合条件的股票\n    qualified_count = 0\n    total_checked = 0\n    \n    for idx, row in cyb_stocks.iterrows():\n        code = row['code']\n        total_checked += 1\n        \n        if total_checked % 50 == 0:\n            print(f\"已检查 {total_checked}/{len(cyb_stocks)} 只股票，当前符合条件: {qualified_count}\")\n        \n        if analyze_stock(code, client):\n            qualified_count += 1\n    \n    print(f\"\\n分析完成！\")\n    print(f\"总共检查: {total_checked} 只股票\")\n    print(f\"符合条件的股票总数: {qualified_count}\")\n    \n    # 写入结果文件\n    output_file = f\"{result_dir}/macd_strength_count.txt\"\n    with open(output_file, 'w', encoding='utf-8') as f:\n        f.write(f\"符合条件的股票总数: {qualified_count}\\n\")\n    \n    print(f\"结果已写入: {output_file}\")\n    \n    return qualified_count\n\nif __name__ == \"__main__\":\n    result = main()\n```🛠️ **正在调用工具:** `code_run`  📥**参数:**\n````text\n{\n  \"type\": \"python\",\n  \"timeout\": 360\n}\n````\n**LLM Running (Turn 5) ...**\n\n<summary>创业板股票筛选失败(0只)，探测stocks()返回数据结构</summary>\n\n\n\n```python\nfrom mootdx.quotes import Quotes\n\nclient = Quotes.factory(market='std')\n\n# 获取股票列表\nstock_list = client.stocks(market=1)  # market=1 深圳\n\nprint(\"股票列表前10行:\")\nprint(stock_list.head(10))\nprint(\"\\n列名:\")\nprint(stock_list.columns.tolist())\nprint(\"\\n数据类型:\")\nprin