{"type":"user","message":{"role":"user","content":[{"tool_use_id":"tooluse_b7k4Wgl4y4r4vmwn170JmX","type":"tool_result","content":"The file /Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_10_macd_histogram_trend/revised/claudecode/analyze_macd.py has been updated successfully."}]},"parent_tool_use_id":null,"session_id":"1735def6-7d8f-4f06-8f4b-6eb7cb1accac","uuid":"b2749575-fdec-4cf1-b64e-3d104d96542b","timestamp":"2026-04-14T12:53:45.227Z","tool_use_result":{"filePath":"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_10_macd_histogram_trend/revised/claudecode/analyze_macd.py","oldString":"    # 获取创业板股票列表\n    print(\"获取创业板股票列表...\")\n    try:\n        stock_list = ak.stock_zh_a_spot_em()\n        cyb_stocks = stock_list[stock_list['代码'].str.startswith(('300', '301'))]\n        print(f\"找到 {len(cyb_stocks)} 只创业板股票\")\n    except Exception as e:\n        print(f\"获取股票列表失败: {e}\")\n        return","newString":"    # 获取创业板股票列表\n    print(\"获取创业板股票列表...\")\n    try:\n        stock_list = ak.stock_info_a_code_name()\n        cyb_stocks = stock_list[stock_list['code'].str.startswith(('300', '301'))]\n        print(f\"找到 {len(cyb_stocks)} 只创业板股票\")\n    except Exception as e:\n        print(f\"获取股票列表失败: {e}\")\n        return","originalFile":"#!/usr/bin/env python3\n\"\"\"\n分析创业板股票MACD柱状图从负转正后连续增长超过5天的情况\n\"\"\"\nimport sys\nsys.path.insert(0, '/Users/tomato/Documents/potato/project/YFD')\n\nimport akshare as ak\nimport pandas as pd\nimport numpy as np\nfrom datetime import datetime, timedelta\nfrom tqdm import tqdm\n\ndef calculate_ema(data, period):\n    \"\"\"计算指数移动平均\"\"\"\n    return data.ewm(span=period, adjust=False).mean()\n\ndef calculate_macd(df):\n    \"\"\"计算MACD指标\"\"\"\n    # 计算EMA12和EMA26\n    ema12 = calculate_ema(df['close'], 12)\n    ema26 = calculate_ema(df['close'], 26)\n\n    # 计算DIFF\n    diff = ema12 - ema26\n\n    # 计算DEA (DIFF的9日EMA)\n    dea = calculate_ema(diff, 9)\n\n    # 计算histogram\n    histogram = diff - dea\n\n    return histogram\n\ndef check_consecutive_increase(histogram_series, start_idx, days=5):\n    \"\"\"\n    检查从start_idx开始，histogram是否连续递增至少days天\n    \"\"\"\n    if start_idx + days >= len(histogram_series):\n        return False\n\n    for i in range(days):\n        if histogram_series.iloc[start_idx + i + 1] <= histogram_series.iloc[start_idx + i]:\n            return False\n\n    return True\n\ndef analyze_stock(stock_code, end_date='2024-12-31'):\n    \"\"\"\n    分析单只股票的MACD histogram\n    返回是否满足条件\n    \"\"\"\n    try:\n        # 获取股票数据，需要更多天数用于预热\n        df = ak.stock_zh_a_hist(symbol=stock_code, period=\"daily\",\n                                start_date=\"20240801\", end_date=end_date, adjust=\"qfq\")\n\n        if df is None or len(df) < 90:\n            return False\n\n        # 计算MACD histogram\n        df['histogram'] = calculate_macd(df)\n\n        # 获取最后60个交易日\n        df_60 = df.tail(60).reset_index(drop=True)\n\n        if len(df_60) < 60:\n            return False\n\n        # 查找histogram从负转正的位置\n        found = False\n        for i in range(len(df_60) - 6):  # 至少需要后续5天\n            # 检查是否从负转正\n            if i > 0 and df_60['histogram'].iloc[i-1] < 0 and df_60['histogram'].iloc[i] > 0:\n                # 检查后续5天是否连续递增\n                if check_consecutive_increase(df_60['histogram'], i, 5):\n                    found = True\n                    break\n\n        return found\n\n    except Exception as e:\n        return False\n\ndef main():\n    print(\"开始分析创业板MACD柱状图趋势...\")\n\n    # 获取创业板股票列表\n    print(\"获取创业板股票列表...\")\n    try:\n        stock_list = ak.stock_zh_a_spot_em()\n        cyb_stocks = stock_list[stock_list['代码'].str.startswith(('300', '301'))]\n        print(f\"找到 {len(cyb_stocks)} 只创业板股票\")\n    except Exception as e:\n        print(f\"获取股票列表失败: {e}\")\n        return\n\n    # 分析每只股票\n    count = 0\n    for idx, row in tqdm(cyb_stocks.iterrows(), total=len(cyb_stocks), desc=\"分析进度\"):\n        stock_code = row['代码']\n        if analyze_stock(stock_code):\n            count += 1\n\n    print(f\"\\n分析完成！\")\n    print(f\"符合条件的股票总数: {count}\")\n\n    # 写入结果文件\n    result_path = \"/Users/tomato/Documents/potato/project/YFD/yfd-agent-consensus/results/agent_consensus_batch/default_run/task_10_macd_histogram_trend/revised/claudecode/macd_strength_count.txt\"\n    with open(result_path, 'w', encoding='utf-8') as f:\n        f.write(f\"符合条件的股票总数: {count}\\n\")\n\n    print(f\"结果已写入: {result_path}\")\n\nif __name__ == \"__main__\":\n    main()\n","structuredPatch":[{"oldStart":88,"oldLines":8,"newStart":88,"newLines":8,"lines":["     # 获取创业板股票列表","     print(\"获取创业板股票列表...\")","     try:","-        stock_list = ak.stock_zh_a_spot_em()","-        cyb_stocks = stock_list[stock_list['代码'].str.startswith(('300', '301'))]","+        stock_list = ak.stock_info_a_code_name()","+        cyb_stocks = stock_list[stock_list['code'].str.startswith(('300', '301'))]","         print(f\"找到 {len(cyb_stocks)} 只创业板股票\")","     except Exception as e:","         print(f\"获取股票列表失败: {e}\")"]}],"userModified":false,"replaceAll":false}}
